// // This module monitors the input voltage and sets the output high when the voltage drops below a certain level.
module current_sensor(  
    input wire clk,  
    input wire [3:0] current_in,  
    output reg alarm_out  
);  
    parameter THRESHOLD = 9;  

    always @(posedge clk) begin  
        if (current_in > THRESHOLD)  
            alarm_out <= 1'b1;  
        else  
            alarm_out <= 1'b0;  
    end  
endmodule
